class ETG_InventFairValueReportController extends SrsReportRunController implements BatchRetryable
{
    ETG_InventFairValueHeaderTable inventFairValueHeaderTable ;

}

Method.Source:
public ETG_InventFairValueHeaderTable parmInventFairValueHeaderTable(ETG_InventFairValueHeaderTable _inventFairValueHeaderTable = inventFairValueHeaderTable)
{
    inventFairValueHeaderTable = _inventFairValueHeaderTable;

    return inventFairValueHeaderTable;
}

public static ETG_InventFairValueReportController construct()
{
    return new ETG_InventFairValueReportController();
}

public static void main(Args _args)
{

    ETG_InventFairValueReportController controller =ETG_InventFairValueReportController::construct();
    controller.parmReportName(ssrsReportStr(ETG_InventFairValueReport, PrecisionDesign));
   //controller.parmReportContract().parmReportCaption("Inventory fair valuation data");
    controller.parmArgs(_args);
    controller.parmReportContract().parmReportCaption("Inventory fair valuation data") ;
    controller.parmshowDialog(true);
    controller.parmInventFairValueHeaderTable(_args.caller().parmInventFairValueHeaderTable());
    //controller.parmDialogCaption("Inventory fair valuation data ");
    controller.startOperation();
}

public SysOperationStartResult startOperation()
{
    SysOperationStartResult ret;

    this.getDataContractObject().parmInventFairValueHeaderTable(this.parmInventFairValueHeaderTable());
    this.getDataContractObject().parmFairValuationSerialNumber(this.parmInventFairValueHeaderTable().FairValuationSerialNumber) ;
    this.getDataContractObject().parmConfig(this.parmInventFairValueHeaderTable().Grade) ;
    this.getDataContractObject().parmSize(this.parmInventFairValueHeaderTable().Size) ;
    this.getDataContractObject().parmColor(this.parmInventFairValueHeaderTable().Origin) ;
    this.getDataContractObject().parmStyle(this.parmInventFairValueHeaderTable().Brand) ;
    this.getDataContractObject().parmSite(this.parmInventFairValueHeaderTable().Site) ;
    this.getDataContractObject().parmWarehouse(this.parmInventFairValueHeaderTable().Warehouse) ;
    this.getDataContractObject().parmLocation(this.parmInventFairValueHeaderTable().Location) ;
    this.getDataContractObject().parmBatchNumber(this.parmInventFairValueHeaderTable().BatchNumber) ;

    ret = super();

    return ret;
}

/// <summary>
